import TimeBox from "./TimeBox"
import ProcessorBox from "./ProcessorBox"

export class Processor extends Component {
    render() {
        return (
            <div>
                <div style={processorContainer}></div>
                <TimeBox/>
                <ProcessorBox/>
                <TimeBox/>
            </div>
        )
    }
}

export default Processor

const processorContainer = {
    padding: "10px"
}
